 19→function useUnits() {
 20→  const [unit, setUnit] = useState('mm');
 21→  const isMm = unit === 'mm';
 22→  return {
 23→    unit,
 24→    setUnit,
 25→    suffix: isMm ? 'mm' : 'm',
 26→    toDisplay: (mm) => isMm ? Math.round(mm) : +(mm / 1000).toFixed(3),
 27→    fromDisplay: (v) => isMm ? v : v * 1000,
 28→    step: (mmStep) => isMm ? mmStep : mmStep / 1000,
 29→  };
 30→}
